## 6. Dictionary & Set Operations
# Dictionary to store employee details (EmployeeID: Name)

employees = {}    #Empty Distctionary

# Sets to store departments
department_CSE = {"E101", "E102", "E103", "E104"}
department_AIML = {"E103", "E104", "E105", "E106"}

# Function to add an employee
def add_employee():
    emp_id = input("Enter Employee ID: ")

    if emp_id in employees:
        print("Employee ID already exists!\n")
        return

    emp_name = input("Enter Employee Name: ")
    employees[emp_id] = emp_name
    print("Employee ",emp_name," added successfully")

# Function to remove an employee
def remove_employee():
    emp_id = input("Enter Employee ID to remove: ")

    if emp_id in employees:
        del employees[emp_id]
        print(f"Employee with ID {emp_id} removed successfully\n")
    else:
        print("Employee ID not found\n")

# Function to search for an employee
def search_employee():
    emp_id = input("Enter Employee ID to search: ")

    if emp_id in employees:
        print(f"Employee Found: {emp_id} -> {employees[emp_id]}\n")
    else:
        print("Employee ID not found")

# Function to display all employees sorted by name
def display_sorted_employees():
    if not employees:
        print("No employees in the database")
        return

    print("Employees sorted by name:")
    for emp_id, emp_name in sorted(employees.items(), key=lambda x: x[1]):
        print(f"{emp_id}: {emp_name}")
    print()

# Function to perform set operations on departments
def perform_set_operations():
    print("\nSet Operations on Departments:")
    print(f"Department A: {department_CSE}")
    print(f"Department B: {department_AIML}")

    print("\nUnion (Employees in either A or B):", department_CSE | department_AIML)
    print("Intersection (Employees in both A and B):", department_CSE & department_AIML)
    print("Difference (Employees in A but not in B):", department_CSE - department_AIML)
    print("Difference (Employees in B but not in A):", department_CSE - department_AIML, "\n")

# Menu-driven approach
while True:
    print("Employee Database Management System")
    print("1. Add Employee")
    print("2. Remove Employee")
    print("3. Search Employee")
    print("4. Display Employees in Sorted Order")
    print("5. Perform Set Operations on Departments")
    print("6. Exit")

    choice = input("Enter your choice (1-6): ")

    if choice == "1":
        add_employee()
    elif choice == "2":
        remove_employee()
    elif choice == "3":
        search_employee()
    elif choice == "4":
        display_sorted_employees()
    elif choice == "5":
        perform_set_operations()
    elif choice == "6":
        print("Exiting program...")
        break
    else:
        print("Invalid choice, Please enter a number between 1 and 6\n")
